function bestColumn(headers, hints){let norm=headers.map(h=>[h,normHeader(h)]); let best='', score=0; for(let [h,nh] of norm){for(let term of hints){let nt=normHeader(term); let s=0; if(nh===nt) s=10; else if(nh.includes(nt)||nt.includes(nh)) s=5; else {let words=nt.split(' ').filter(w=>w.length>2); if(words.length && words.every(w=>nh.includes(w))) s=3} if(s>score){score=s; best=h}}} return score?best:''}
function parseNumberishDate(v){if(v instanceof Date && !isNaN(v)) return v; if(v==null||v==='') return null; let n=num(v); if(n!==null && n>20000) return new Date(Date.UTC(1899,11,30)+Math.floor(n)*MS_DAY); let t=Date.parse(String(v)); return Number.isFinite(t)?new Date(t):null}
function toExcelSerial(d){return d?String(Math.floor((Date.UTC(d.getUTCFullYear(),d.getUTCMonth(),d.getUTCDate())-Date.UTC(1899,11,30))/MS_DAY)):''}
function chooseRelevantSheet(workbook){let best={name:workbook.SheetNames[0], rows:[], score:-1}; for(let name of workbook.SheetNames){let rows=XLSX.utils.sheet_to_json(workbook.Sheets[name],{defval:'',raw:false}); if(!rows.length) continue; let headers=Object.keys(rows[0]||{}); let score=0; for(let hints of Object.values(FIELD_HINTS)){if(bestColumn(headers,hints)) score++} score += Math.min(rows.length/1000,3); if(score>best.score) best={name,rows,score}} return best}
function normaliseUploadedRows(inputRows){let headers=Object.keys(inputRows[0]||{}); let map={}; for(let [field,hints] of Object.entries(FIELD_HINTS)) map[field]=bestColumn(headers,hints); let out=inputRows.map((r,i)=>{let o={}; for(let field of Object.keys(FIELD_HINTS)) o[field]=map[field]?String(r[map[field]]??''):''; if(!o['Project Code']) o['Project Code']=String(r[map['Project Code']]||r.Project||r.project||`Project ${i+1}`); if(!o['Task Name']) o['Task Name']=String(r[map['Task Name']]||r.Task||r.task||r.Activity||'Task'); let created=parseNumberishDate(o['Date Created']), start=parseNumberishDate(o['Start Date'])||created, due=parseNumberishDate(o['Due Date']), done=parseNumberishDate(o['Completion Date']); o['Date Created']=toExcelSerial(created); o['Start Date']=toExcelSerial(start); o['Due Date']=toExcelSerial(due); o['Completion Date']=toExcelSerial(done); let target=num(o['Target Days to complete']); if(target===null){let task=(o['Task Name']||'').toLowerCase(); target=task.includes('first patient')||task.includes('1st patient')?30:task.includes('green light')||task.includes('siv')?14:task.includes('local information')?0:7; o['Target Days to complete']=String(target)} let completed=!!done || /complete|closed|done/i.test(o['Task Status']); if(!o['Task Status']) o['Task Status']=completed?'Complete':'Active'; if(!o['Days to completion'] && done && (start||created)) o['Days to completion']=String(Math.max(0,Math.round((done-(start||created))/MS_DAY))); if(!o['Days active (if not complete)'] && !completed && (start||created)) o['Days active (if not complete)']=String(Math.max(0,Math.round((new Date()-(start||created))/MS_DAY))); if(!o['On time or Late']){let elapsed=num(completed?o['Days to completion']:o['Days active (if not complete)']); o['On time or Late']=completed?(Number.isFinite(elapsed)&&Number.isFinite(target)&&elapsed<=target?'On Time':'Late'):''} return o}).filter(r=>r['Project Code']||r['Task Name']); return {rows:out,map}}
async function handleUpload(ev){let file=ev.target.files?.[0]; if(!file) return; let status=document.getElementById('uploadStatus'); try{if(status) status.textContent='Reading file…'; let buf=await file.arrayBuffer(); let wb=XLSX.read(buf,{type:'array',cellDates:true}); let chosen=chooseRelevantSheet(wb); if(!chosen.rows.length) throw new Error('No tabular rows found'); let normalised=normaliseUploadedRows(chosen.rows); let packed=packRows(normalised.rows); localStorage.setItem(UPLOAD_KEY,packed); localStorage.setItem(UPLOAD_META_KEY,JSON.stringify({uploaded:true,name:file.name,sheet:chosen.name,nRows:normalised.rows.length,storageMb:(packed.length/1048576).toFixed(2),note:`Mapped ${Object.values(normalised.map).filter(Boolean).length} fields from sheet ${chosen.name}`})); location.reload()}catch(e){if(status) status.textContent=`Could not import file: ${e.name==='QuotaExceededError'?'This file is still too large for browser storage. Try clearing site data or use the hosted bundled dataset.':e.message}`; console.error(e)}}

function num(x){let n=parseFloat(x); return Number.isFinite(n)?n:null}
function excelDate(x){if(x instanceof Date && !isNaN(x)) return x; if(x==null||x==='') return null; let n=num(x); if(n!==null && n>20000) return new Date(Date.UTC(1899,11,30)+Math.floor(n)*MS_DAY); let t=Date.parse(String(x)); return Number.isFinite(t)?new Date(t):null}
function fmtDate(d){return d?d.toISOString().slice(0,10):''}
function median(a){a=a.filter(Number.isFinite).sort((a,b)=>a-b); if(!a.length)return null; let m=Math.floor(a.length/2); return a.length%2?a[m]:(a[m-1]+a[m])/2}
function mean(a){a=a.filter(Number.isFinite); return a.length?a.reduce((s,x)=>s+x,0)/a.length:null}
function pct(n,d){return d?Math.round(1000*n/d)/10:0}
function esc(s){return String(s ?? '').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
function normTask(s){return (s||'').trim().replace(/\s+/g,' ')}
function daysLate(r){if(r.taskStatus==='Complete') return Math.max(0,(r.daysToCompletion??0)-(r.targetDays??0)); if(r.dueDate && r.isOpen) return Math.max(0,Math.floor((new Date()-r.dueDate)/MS_DAY)); return 0}
