function categoryFor(r){let text=((r.task||'')+' '+(r.taskComment||'')).toLowerCase().replace(/[^a-z0-9/]+/g,' '); let best='Other / uncategorised', bestScore=0; CATEGORY_RULES.forEach(([cat,terms])=>{let score=0; terms.forEach(term=>{let t=term.toLowerCase().trim(); if(!t)return; if(text.includes(t)) score+=t.length>12?4:2; else {let words=t.split(/\s+/).filter(w=>w.length>3); if(words.length && words.every(w=>text.includes(w))) score+=1.5}}); if(score>bestScore){bestScore=score;best=cat}}); return best}
