function taskCols(){return [{label:'Project',key:'project'},{label:'Workflow',key:'workflow'},{label:'Task type',key:'taskType'},{label:'Assigned to',key:'assignee'},{label:'Order',f:r=>r.workflowOrder??'',sort:r=>r.workflowOrder??9999},{label:'Category',key:'category'},{label:'Task',key:'task'},{label:'Task status',key:'taskStatus'},{label:'Start',f:r=>fmtDate(r.startDate),sort:r=>fmtDate(r.startDate)},{label:'Completed',f:r=>fmtDate(r.completionDate),sort:r=>fmtDate(r.completionDate)},{label:'Completion duration',f:r=>Number.isFinite(r.taskDuration)?r.taskDuration+' days':'NA',sort:r=>r.taskDuration??-1},{label:'Active age',f:r=>r.isOpen&&Number.isFinite(r.daysActive)?r.daysActive+' days':'',sort:r=>r.daysActive??-1},{label:'Due',f:r=>fmtDate(r.dueDate),sort:r=>fmtDate(r.dueDate)},{label:'Comment',f:r=>`<span class="small">${esc((r.taskComment||'').slice(0,220))}</span>`}]}
function compactCounts(arr,keyFn){return [...group(arr,keyFn)].map(([name,items])=>({name:name||'Unspecified',n:items.length,active:items.filter(r=>r.isOpen).length,complete:items.filter(r=>r.taskStatus==='Complete').length,medianDuration:median(items.filter(r=>r.taskStatus==='Complete').map(r=>r.taskDuration).filter(Number.isFinite)),oldestActive:items.filter(r=>r.isOpen).map(r=>r.daysActive||0).reduce((a,b)=>Math.max(a,b),0)})).sort((a,b)=>b.n-a.n||String(a.name).localeCompare(String(b.name)))}
function projectTaskBreakdownHtml(rs){let byStatus=compactCounts(rs,r=>r.taskStatus), byType=compactCounts(rs,r=>r.taskType||r.category).slice(0,8), byOwner=compactCounts(rs,r=>r.assignee||'Unassigned').slice(0,8), active=rs.filter(r=>r.isOpen).sort((a,b)=>(b.daysActive||0)-(a.daysActive||0)).slice(0,6); let miniTable=(title,items)=>`<div class="card"><h4>${esc(title)}</h4><div class="tablewrap" style="max-height:260px"><table><thead><tr><th>Group</th><th>Tasks</th><th>Active</th><th>Median completion</th><th>Oldest active</th></tr></thead><tbody>${items.map(x=>`<tr><td>${esc(x.name)}</td><td>${x.n}</td><td>${x.active}</td><td>${x.medianDuration??'–'} days</td><td>${x.oldestActive||'–'} days</td></tr>`).join('')}</tbody></table></div></div>`; return `<div class="grid two" style="margin:12px 0">${miniTable('Task status breakdown',byStatus)}${miniTable('Top task types',byType)}</div><div class="grid two" style="margin:12px 0">${miniTable('Assigned owner / team',byOwner)}<div class="card"><h4>Longest active tasks</h4><div class="tablewrap" style="max-height:260px"><table><thead><tr><th>Task</th><th>Type</th><th>Assigned to</th><th>Active age</th></tr></thead><tbody>${active.length?active.map(r=>`<tr><td>${esc(r.task)}</td><td>${esc(r.taskType||r.category)}</td><td>${esc(r.assignee||'Unassigned')}</td><td>${r.daysActive??'–'} days</td></tr>`).join(''):'<tr><td colspan="4" class="small">No active tasks in this project.</td></tr>'}</tbody></table></div></div></div>`}
