window.showProject=function(code){let p=pAgg.find(x=>x.project===code); if(!p)return; let rs=p.tasks.slice().sort((a,b)=>((a.workflowOrder??9999)-(b.workflowOrder??9999)) || ((a.startDate||a.createdDate||0)-(b.startDate||b.createdDate||0))); let completedDurations=rs.filter(r=>r.taskStatus==='Complete').map(r=>r.taskDuration).filter(Number.isFinite); document.getElementById('projectDetail').innerHTML=`<h3>${esc(p.project)}</h3><div class="pillrow"><span class="metric"><b>${esc(p.projectStatus)}</b><br>Status</span><span class="metric"><b>${esc(p.studyType||'Unspecified')}</b><br>Project type</span><span class="metric"><b>${projectTargetStatus(p)}</b><br>Target status</span><span class="metric"><b>${p.n}</b><br>Tasks</span><span class="metric"><b>${p.active}</b><br>Active</span><span class="metric"><b>${median(completedDurations)??'–'} days</b><br>Median task completion</span><span class="metric"><b>${Number.isFinite(p.setupDays)?p.setupDays+' days':'–'}</b><br>Start→C&C target</span><span class="metric"><b>${fmtDate(p.capacityDate)||'–'}</b><br>C&C confirmation</span><span class="metric"><b>${Number.isFinite(p.greenToFirst)?p.greenToFirst+' days':'–'}</b><br>Green→1st pt</span><span class="metric"><b>${p.maxActive} days</b><br>Oldest active</span></div><p class="small"><b>Interpretation:</b> project targets use the two start/end intervals above. Task detail below is task-specific: workflow order, each task’s own start/completion dates, active age, type, and assigned owner/team.</p><h4>Task breakdown</h4>${projectTaskBreakdownHtml(rs)}<h4>Task timeline</h4><div id="projectMini" class="plot"></div><h4>Project task records</h4><div class="tablewrap project-task-wrap"><table id="projectTasks"></table></div>`; renderTable('projectTasks',projectTaskCols(),rs,300); setTimeout(()=>drawProjectGantt('projectMini',rs),20)}
function initTasks(){document.getElementById('taskStatusFilter').innerHTML += [...new Set(rows.map(r=>r.taskStatus))].sort().map(s=>`<option>${esc(s)}</option>`).join(''); document.getElementById('taskCategoryFilter').innerHTML += CATEGORY_RULES.map(x=>x[0]).map(s=>`<option>${esc(s)}</option>`).join(''); let cats=cAgg.slice(0,24).reverse(), durationCats=cAgg.slice().sort((a,b)=>(b.meanDays||0)-(a.meanDays||0)).slice(0,24).reverse(); plot('categoryDelayPlot',[{type:'bar',orientation:'h',y:barLabels(durationCats.map(c=>c.category),36),x:durationCats.map(c=>Math.round(c.meanDays*10)/10),customdata:durationCats.map(c=>c.category),text:durationCats.map(c=>`${Math.round((c.meanDays||0)*10)/10} days · ${c.active} active`),hovertemplate:'%{customdata}<br>Mean completion duration: %{x} days<br>%{text}<extra></extra>',marker:{color:durationCats.map(c=>c.meanDays||0),colorscale:'YlOrRd'}}],{title:'Task categories by mean completion duration',...horizontalBarLayout(barLabels(durationCats.map(c=>c.category),36)),xaxis:{title:'mean completion days'}}); plot('categoryMixPlot',[{type:'bar',orientation:'h',y:barLabels(cats.map(c=>c.category),36),x:cats.map(c=>c.n),name:'all tasks'},{type:'bar',orientation:'h',y:barLabels(cats.map(c=>c.category),36),x:cats.map(c=>c.active),name:'active/pending'}],{title:'Workload by category',barmode:'stack',...horizontalBarLayout(barLabels(cats.map(c=>c.category),36)),xaxis:{title:'records'}}); let top=tAgg.slice(0,22).reverse(); let topLabels=barLabels(top.map(t=>t.task),58); plot('taskTypePlot',[{type:'bar',orientation:'h',y:topLabels,x:top.map(t=>t.bottleneckScore),customdata:top.map(t=>t.task),hovertemplate:'%{customdata}<br>Bottleneck score: %{x}<extra></extra>',marker:{color:'#b45309'}}],{title:'Task names by completion-duration / active-backlog score',...horizontalBarLayout(topLabels,{xaxis:{title:'score'}})}); plot('taskPerfPlot',[{type:'scatter',mode:'markers',x:tAgg.map(t=>t.active),y:tAgg.map(t=>t.meanDuration),text:tAgg.map(t=>t.task),hovertemplate:'%{text}<br>Active records %{x}<br>Mean completion duration %{y:.1f} days<extra></extra>',marker:{size:tAgg.map(t=>Math.max(7,Math.min(30,t.n))),color:tAgg.map(t=>t.active),colorscale:'Viridis',showscale:true,colorbar:{title:'active'}}}],{title:'Task type performance map',xaxis:{title:'active records'},yaxis:{title:'mean completion duration days'}}); ['taskSearch','taskStatusFilter','taskTimingFilter','taskCategoryFilter'].forEach(id=>document.getElementById(id).addEventListener('input',renderTasks)); renderTasks()}
function renderTasks(){let q=document.getElementById('taskSearch').value.toLowerCase(), st=document.getElementById('taskStatusFilter').value, tf=document.getElementById('taskTimingFilter').value, cat=document.getElementById('taskCategoryFilter').value; let data=rows.filter(r=>(!q||(r.task+' '+r.project+' '+r.taskComment+' '+r.category).toLowerCase().includes(q))&&(!st||r.taskStatus===st)&&(!cat||r.category===cat)&&(!tf||(tf==='Active/Pending'?r.taskStatus!=='Complete':r.timing===tf))).sort((a,b)=>(b.isOpen-a.isOpen)||(b.lateDays-a.lateDays)||((b.elapsed||0)-(a.elapsed||0))); renderTable('taskTable',taskCols(),data,1200)}
function initBottlenecks(){let cats=cAgg.slice(0,15).reverse(), catLabels=barLabels(cats.map(c=>c.category),34); plot('bottleneckPlot',[{type:'bar',orientation:'h',y:catLabels,x:cats.map(c=>c.bottleneckScore),marker:{color:'#dc2626'}}],{title:'Categories by bottleneck score',...horizontalBarLayout(catLabels,{xaxis:{title:'bottleneck score'}})}); let active=rows.filter(r=>r.isOpen).sort((a,b)=>(b.daysActive||0)-(a.daysActive||0)).slice(0,15).reverse(), activeLabels=barLabels(active.map(r=>`${r.project} · ${r.task}`),44); plot('overduePlot',[{type:'bar',orientation:'h',y:activeLabels,x:active.map(r=>r.daysActive||0),marker:{color:'#dc2626'},hovertext:active.map(r=>`${r.project}<br>${esc(r.task)}<br>${r.daysActive||0} days active`),hoverinfo:'text'}],{title:'Longest-running unresolved tasks',...horizontalBarLayout(activeLabels,{margin:{l:310,r:30,t:55,b:85},xaxis:{title:'days active'}})}); let activeRows=rows.filter(r=>r.isOpen).sort((a,b)=>(b.lateDays-a.lateDays)||((b.daysActive||0)-(a.daysActive||0))); renderTable('bottleneckTable',taskCols(),activeRows,100); renderTable('resourceTable',[{label:'Category',key:'category'},{label:'Projects',key:'projects'},{label:'Records',key:'n'},{label:'Active',key:'active'},{label:'Overdue',key:'overdue'},{label:'>60 days active',key:'over60'},{label:'Late rate',f:c=>c.lateRate+'%'},{label:'Mean completion duration',f:c=>Math.round((c.meanDays||0)*10)/10+' days',sort:c=>c.meanDays},{label:'Missed setup projects',key:'missedSetupProjects'},{label:'Resource score',key:'bottleneckScore'}],cAgg,100)}
const OP_THEMES=[
 {name:'Document pack / local information completeness',terms:['local information pack','document pack','hra approval','iras','oid','pis','icf','protocol','delegation log','missing documents'],interpretation:'Repeated delays here usually indicate incomplete or late sponsor document transfer, localising/checking document packs, or rework needed before setup can proceed. This is a good candidate for earlier document triage/checklists and dedicated admin capacity.'},
 {name:'Finance, costing and invoicing',terms:['finance','costing','cost code','invoice','invoicing','reconciliation','setup fees','set-up fees','cpms','soecat'],interpretation:'These records point to costing, finance review, cost-code creation and invoicing as operational pinch-points. Extra finance/R&D office capacity or clearer commercial/non-commercial routing may improve throughput.'},
 {name:'Support department capacity checks',terms:['pharmacy','labs','laboratory','ribs','biospecimen','biobank','imaging','access imaging','drug storage','pharmacy manual'],interpretation:'Delays cluster around specialist support departments. The comments suggest dependency on minimum datasets, manuals, sample/storage details and departmental capacity-and-capability confirmation.'},
 {name:'Governance, risk assessment and approvals',terms:['risk assessment','planning review','clinical director','notification','regulatory','approval','ethics','amendment'],interpretation:'These are internal governance steps. Delays may reflect hand-offs for risk assessment, sign-off, clinical director notification or governance review rather than purely sponsor-side delay.'},
 {name:'Sponsor hand-off / site selected / trust invited',terms:['trust invited','trust selected','site invited','site selected','sponsor email','sponsor requests','information to mft','start set-up'],interpretation:'These comments relate to the setup start date. Bottlenecks here may be poor timestamp quality, unclear sponsor handover, or delayed transfer of complete information needed to begin setup.'},
 {name:'Green light and recruitment activation',terms:['green light','recruitment can commence','siv','site initiation','recruitment plan','retention plan'],interpretation:'These records sit close to setup completion. Delays here may represent final activation steps, SIV scheduling or unresolved prerequisites blocking green light.'},
 {name:'First patient / recruitment delivery',terms:['1st patient','first patient','first eligible patient','consented','delay reasons','patient recruited','non-recruiting'],interpretation:'These tasks map to the 30-day green-light-to-first-consent target. Delays may need study-team recruitment planning support rather than setup-process resource alone.'},
 {name:'Systems / Hive / access build',terms:['hive','ehr','build request','researchcontent','system','database','access','account','login'],interpretation:'These records suggest digital build/access dependencies. If recurrent, a standardised early Hive/EHR request workflow may reduce late activation delays.'},
 {name:'Service support / NHS support costs',terms:['service support','nhs support','lcrn','resource','support costs','director of research delivery'],interpretation:'These comments suggest uncertainty about support costs or service implications. Delays may benefit from earlier escalation and decision ownership.'}
];
function delayedForThemes(){return rows.filter(r=>r.timing==='Late'||r.lateDays>0||r.overTarget>0||(r.isOpen&&Number.isFinite(r.daysActive)&&r.daysActive>30))}
function themeForRecord(r){let text=((r.task||'')+' '+(r.taskComment||'')+' '+(r.category||'')).toLowerCase(); let best=null, score=0; OP_THEMES.forEach(t=>{let s=0; t.terms.forEach(term=>{if(text.includes(term)) s += term.length>12?3:1}); if(s>score){score=s; best=t}}); return best || {name:'Other operational hand-offs',terms:[],interpretation:'Delayed records not captured by the predefined themes. These should be reviewed manually for local process-specific constraints.'}}
function themeAgg(){let delayed=delayedForThemes(), m=new Map(); delayed.forEach(r=>{let t=themeForRecord(r); if(!m.has(t.name)) m.set(t.name,{...t,records:[],projects:new Set(),late:0,active:0,over60:0,totalDelay:0}); let x=m.get(t.name); x.records.push(r); x.projects.add(r.project); if(r.timing==='Late') x.late++; if(r.isOpen) x.active++; if((r.daysActive||0)>60) x.over60++; x.totalDelay += r.overTarget||r.lateDays||0}); return [...m.values()].map(x=>({...x,projectsN:x.projects.size,n:x.records.length,meanElapsed:mean(x.records.map(r=>r.elapsed))||0,meanDelay:x.records.length?x.totalDelay/x.records.length:0,score:Math.round(x.n*2+x.active*3+x.over60*8+x.meanDelay+x.projectsN)})).sort((a,b)=>b.score-a.score)}
function initThemes(){let themes=themeAgg(); let top=themes.slice(0,8); document.getElementById('themeNarrative').innerHTML=top.map(t=>{let examples=t.records.slice().sort((a,b)=>(b.elapsed||0)-(a.elapsed||0)).slice(0,3).map(r=>`<li><b>${esc(r.project)}</b>: ${esc(r.task)} <span class="muted">(${r.elapsed??'–'} days; ${esc(r.taskStatus)})</span><br><span class="small">${esc((r.taskComment||'').slice(0,210))}</span></li>`).join(''); return `<div class="card"><h3>${esc(t.name)}</h3><div class="pillrow"><span class="metric"><b>${t.n}</b><br>Delayed records</span><span class="metric"><b>${t.projectsN}</b><br>Projects</span><span class="metric"><b>${t.active}</b><br>Active</span><span class="metric"><b>${t.over60}</b><br>>60 days active</span><span class="metric"><b>${Math.round(t.meanElapsed*10)/10} days</b><br>Mean elapsed</span></div><p>${esc(t.interpretation)}</p><p class="small"><b>Evidence examples</b></p><ul class="small">${examples}</ul></div>`}).join(''); let rev=[...top].reverse(), themeLabels=barLabels(rev.map(t=>t.name),38); plot('themeBurdenPlot',[{type:'bar',orientation:'h',y:themeLabels,x:rev.map(t=>t.n),name:'delayed records'},{type:'bar',orientation:'h',y:themeLabels,x:rev.map(t=>t.active),name:'active'}],{title:'Thematic burden among delayed records',barmode:'stack',...horizontalBarLayout(themeLabels,{xaxis:{title:'records'}})}); plot('themeDelayPlot',[{type:'bar',orientation:'h',y:themeLabels,x:rev.map(t=>Math.round(t.meanElapsed*10)/10),marker:{color:rev.map(t=>t.over60>0?'#dc2626':'#b45309')}}],{title:'Mean elapsed/active days by operational theme',...horizontalBarLayout(themeLabels,{xaxis:{title:'days'}})}); let delayed=delayedForThemes().map(r=>({...r,theme:themeForRecord(r).name})).sort((a,b)=>(b.elapsed||0)-(a.elapsed||0)); renderTable('themeTable',[{label:'Theme',key:'theme'},{label:'Project',key:'project'},{label:'Category',key:'category'},{label:'Task',key:'task'},{label:'Status',key:'taskStatus'},{label:'Elapsed/active',f:r=>r.elapsed??'',sort:r=>r.elapsed??-1},{label:'Delay',f:r=>r.overTarget?`<span class="badge late">+${r.overTarget} days</span>`:'',sort:r=>r.overTarget||0},{label:'Comment',f:r=>`<span class="small">${esc((r.taskComment||'').slice(0,260))}</span>`}],delayed,1200)}

function projectAggFor(sourceRows){return [...group(sourceRows,'project')].map(([project,rs])=>{let active=rs.filter(r=>r.isOpen), comp=rs.filter(r=>r.taskStatus==='Complete'), late=comp.filter(r=>r.timing==='Late'), over60=active.filter(r=>(r.daysActive||0)>60), over30=active.filter(r=>(r.daysActive||0)>30), elapsed=rs.map(r=>r.elapsed).filter(Number.isFinite), activeAge=active.map(r=>r.daysActive).filter(Number.isFinite), overdue=active.filter(r=>r.lateDays>0); let start=setupStart(rs), end=setupEnd(rs), cc=capacityConfirmationRow(rs), gl=greenLightRow(rs), fp=firstPatientRow(rs), capacityDate=endpointDate(cc), greenDate=gl?gl.completionDate:null, fpDate=endpointDate(fp), setupDays=daysBetween(start,capacityDate), startToGreen=setupDays, greenToFirst=daysBetween(greenDate,fpDate); let missSetup=Number.isFinite(setupDays)?setupDays>60:false, missFirst=Number.isFinite(greenToFirst)?greenToFirst>30:false; let score=overdue.length*7 + over60.length*12 + over30.length*4 + active.reduce((s,r)=>s+(r.overTarget||0),0) + late.length*1.5 + (mean(elapsed)||0)*0.15 + (missSetup?30:0) + (missFirst?20:0); let band=score>140?'Critical':score>60?'High':score>20?'Moderate':'Low'; return {project,projectStatus:rs[0]?.projectStatus||'Unknown',studyType:(rs.find(r=>r.studyType)?.studyType||'Unspecified project type').trim(),n:rs.length,complete:comp.length,active:active.length,late:late.length,lateRate:pct(late.length,comp.length||rs.length),medianDays:median(elapsed),meanDays:mean(elapsed),maxActive:activeAge.length?Math.max(...activeAge):0,overdue:overdue.length,over30:over30.length,over60:over60.length,setupStart:start,setupEnd:end,capacityDate,greenDate,fpDate,anchorSource:projectAnchorSource(rs),setupDays,startToGreen,greenToFirst,missSetup,missFirst,riskScore:Math.round(score),riskBand:band,tasks:rs}}).sort((a,b)=>targetPriority(b)-targetPriority(a) || String(a.project).localeCompare(String(b.project)))}
function categoryAggFor(sourceRows,sourcePAgg){return [...group(sourceRows,'category')].map(([category,rs])=>{let comp=rs.filter(r=>r.taskStatus==='Complete'), active=rs.filter(r=>r.isOpen), late=comp.filter(r=>r.timing==='Late'), elapsed=rs.map(r=>r.elapsed).filter(Number.isFinite), delay=rs.map(r=>r.overTarget||r.lateDays||0).filter(Number.isFinite), overdue=active.filter(r=>r.lateDays>0), over60=active.filter(r=>(r.daysActive||0)>60), projectSet=new Set(rs.map(r=>r.project)); let missedSetupProjects=[...projectSet].filter(p=>sourcePAgg.find(x=>x.project===p)?.missSetup).length, missedFirstProjects=[...projectSet].filter(p=>sourcePAgg.find(x=>x.project===p)?.missFirst).length; return {category,n:rs.length,projects:projectSet.size,complete:comp.length,active:active.length,late:late.length,lateRate:pct(late.length,comp.length||rs.length),medianDays:median(elapsed),meanDays:mean(elapsed),medianDelay:median(delay)||0,meanDelay:mean(delay)||0,overdue:overdue.length,over60:over60.length,missedSetupProjects,missedFirstProjects,bottleneckScore:Math.round((mean(delay)||0)*3+late.length+overdue.length*8+over60.length*12+active.length*.5+missedSetupProjects*4+missedFirstProjects*3),rows:rs}}).sort((a,b)=>b.bottleneckScore-a.bottleneckScore)}
function taskDateForReport(r){return r.completionDate||r.dueDate||r.startDate||r.createdDate||lastDateOf(r)}
function reportDateExtent(){let ds=rows.map(taskDateForReport).filter(Boolean).sort((a,b)=>a-b); return {min:ds[0]||null,max:ds[ds.length-1]||null}}
function initReport(){let ex=reportDateExtent(); if(ex.min&&!document.getElementById('reportFrom').value) document.getElementById('reportFrom').value=fmtDate(ex.min); if(ex.max&&!document.getElementById('reportTo').value) document.getElementById('reportTo').value=fmtDate(ex.max); generateReport()}
function reportRows(){let from=excelDate(document.getElementById('reportFrom').value), to=excelDate(document.getElementById('reportTo').value); if(to) to=new Date(to.getTime()+MS_DAY-1); return rows.filter(r=>{let d=taskDateForReport(r); return d && (!from||d>=from) && (!to||d<=to)})}
function plain(s){return esc(String(s??''))}
function reportTable(cols,data,limit=20){return `<table class="report-table"><thead><tr>${cols.map(c=>`<th style="width:${c.w||''}">${esc(c.label)}</th>`).join('')}</tr></thead><tbody>${data.slice(0,limit).map(r=>`<tr>${cols.map(c=>`<td class="${c.num?'num':''}">${c.f?c.f(r):plain(r[c.key])}</td>`).join('')}</tr>`).join('')}</tbody></table>`}
function reportThemeAgg(sourceRows){let delayed=sourceRows.filter(r=>r.timing==='Late'||r.lateDays>0||r.overTarget>0||(r.isOpen&&Number.isFinite(r.daysActive)&&r.daysActive>30)), m=new Map(); delayed.forEach(r=>{let t=themeForRecord(r); if(!m.has(t.name))m.set(t.name,{...t,records:[],projects:new Set(),active:0,over60:0,totalDelay:0}); let x=m.get(t.name); x.records.push(r); x.projects.add(r.project); if(r.isOpen)x.active++; if((r.daysActive||0)>60)x.over60++; x.totalDelay+=r.overTarget||r.lateDays||0}); return [...m.values()].map(x=>({...x,n:x.records.length,projectsN:x.projects.size,meanElapsed:mean(x.records.map(r=>r.elapsed))||0,meanDelay:x.records.length?x.totalDelay/x.records.length:0,score:Math.round(x.n*2+x.active*3+x.over60*8+x.meanDelay+x.projectsN)})).sort((a,b)=>b.score-a.score)}
function reportDomainNarrative(c,sourceRows){let active=c.rows.filter(r=>r.isOpen).sort((a,b)=>(b.elapsed||0)-(a.elapsed||0)); let topProjects=[...group(c.rows,'project')].map(([p,rs])=>[p,rs.length]).sort((a,b)=>b[1]-a[1]).slice(0,3).map(x=>x[0]).join(', '); let example=active[0]||c.rows.slice().sort((a,b)=>(b.overTarget||0)-(a.overTarget||0))[0]; let issue=c.over60?`${c.over60} active records are already beyond 60 days`:c.overdue?`${c.overdue} active records are overdue`:`${c.lateRate}% of completed records were late`; return `${c.category} affects ${c.projects} projects in this period, especially ${topProjects||'no dominant project cluster'}. ${issue}. ${example?`The most useful immediate review is ${example.project}: ${example.task}, because it is ${example.elapsed??'not'} days old/elapsed and sits in the ${example.taskStatus} state.`:''}`}
function generateReport(){let out=document.getElementById('reportOutput'), status=document.getElementById('reportStatus'); let scoped=reportRows(); let pa=projectAggFor(scoped), ca=categoryAggFor(scoped,pa), themes=reportThemeAgg(scoped); let complete=scoped.filter(r=>r.taskStatus==='Complete'), active=scoped.filter(r=>r.isOpen), late=complete.filter(r=>r.timing==='Late'), from=document.getElementById('reportFrom').value, to=document.getElementById('reportTo').value; let setupVals=pa.map(p=>p.startToGreen).filter(Number.isFinite), recruitVals=pa.map(p=>p.greenToFirst).filter(Number.isFinite), missedSetup=pa.filter(p=>p.missSetup), missedFirst=pa.filter(p=>p.missFirst); let monthGroups=[...group(complete,r=>r.completionDate?fmtDate(r.completionDate).slice(0,7):'Unknown')].filter(x=>x[0]!=='Unknown').sort(); let latestMonths=monthGroups.slice(-3); let trendText=latestMonths.length?`In the latest observed months (${latestMonths.map(x=>x[0]).join(', ')}), completed-task volume was ${latestMonths.map(x=>x[1].length).join(' / ')} records, with late completions ${latestMonths.map(x=>x[1].filter(r=>r.timing==='Late').length).join(' / ')} respectively.`:'There are insufficient dated completions in the selected window to describe a completion trend.'; let topActive=active.slice().sort((a,b)=>(b.lateDays-a.lateDays)||((b.elapsed||0)-(a.elapsed||0))).slice(0,18); let pages=`
<div class="report-page"><div class="report-title"><div><h2>R-PEAK setup and bottleneck report</h2><p class="small">Time-bounded operational report for ${plain(from)} to ${plain(to)}.</p></div><div class="report-meta">Generated ${new Date().toLocaleString()}<br>${scoped.length} records · ${pa.length} projects</div></div><div class="report-kpis"><div class="report-kpi"><b>${pa.length}</b><br>Projects</div><div class="report-kpi"><b>${median(setupVals)??'–'} days</b><br>Median Start→C&C</div><div class="report-kpi"><b>${median(recruitVals)??'–'} days</b><br>Median green→1st patient</div><div class="report-kpi"><b>${pct(late.length,complete.length)}%</b><br>Completed late</div></div><div class="report-section"><h3>Methodology and limits</h3><p>This report uses the currently loaded dashboard dataset and only includes records with a usable created, start, due or completion date inside the selected window. The 60-day setup component is anchored to the later of HRA approval date and Date site selected where both are available and ends at email confirmation of capacity and capability. Where HRA approval is missing, the dashboard uses date site selected, then task start/created date as transparent fallbacks. Start→C&C uses this start date and the email confirmation of capacity and capability task completion date as the setup endpoint; incomplete endpoint tasks are counted to today, not to due date. Green→1st patient starts only once green light has a completion date, and ends at first-patient/first-consent completion date; incomplete first-patient endpoint tasks are counted to today.</p><p>The 150-day clinical trial target is represented operationally by the 60-day setup/open-to-recruit component and the 30-day first-patient component. Bottleneck and resource scores are prioritisation signals combining active backlog, overdue/over-target delay, records active over 60 days, delayed-task volume, and contribution to projects missing the 60/30 components. They are not formal audited performance measures.</p><div class="report-note"><b>Time constraint:</b> all plots, tables and narrative below are restricted to ${plain(from)}–${plain(to)}. Changing the date range and regenerating the report will change the denominators and trends.</div></div></div>
<div class="report-page"><div class="report-section"><h3>Performance over time</h3><p>${trendText} This view is intended to show whether throughput and late completions are moving together over time, rather than only giving a static backlog count.</p><div id="reportTrendPlot" class="report-plot"></div><h3>150-day clinical trial target components</h3><p>${missedSetup.length}/${setupVals.length} projects with a measurable Start→C&C interval exceed 60 days. ${missedFirst.length}/${recruitVals.length} projects with a measurable green→first-patient interval exceed 30 days. Projects in the upper tail should be reviewed for whether delay is due to document hand-off, support-department confirmation, finance/costing, SIV/activation, or recruitment delivery after green light.</p><div id="reportSetupPlot" class="report-plot"></div></div></div>
<div class="report-page"><div class="report-section"><h3>Projects by target overrun</h3><p>These projects are ordered by the two core project intervals, prioritising Start→C&C overrun and green→first-patient overrun. The table is deliberately narrow so that it fits A4 output.</p>${reportTable([{label:'Project',key:'project',w:'18%'},{label:'Status',key:'projectStatus',w:'15%'},{label:'Target status',f:p=>(p.setupDays>60||p.greenToFirst>30)?'Review':'On target',w:'10%'},{label:'Tasks',key:'n',num:true,w:'7%'},{label:'Active',key:'active',num:true,w:'7%'},{label:'Start→C&C',f:p=>Number.isFinite(p.startToGreen)?p.startToGreen+' days':'–',num:true,w:'10%'},{label:'Green→1st',f:p=>Number.isFinite(p.greenToFirst)?p.greenToFirst+' days':'–',num:true,w:'10%'},{label:'Oldest active',f:p=>p.maxActive+' days',num:true,w:'10%'},{label:'Overrun priority',f:p=>Math.round(targetPriority(p)),num:true,w:'8%'}],pa.slice(0,18),18)}</div></div>
<div class="report-page"><div class="report-section"><h3>Task domains and operational interpretation</h3><p>The domains below are ranked by resource/bottleneck score in the selected window. Narrative statements are generated from the actual projects, task states and comments in each domain, so they should be read as prompts for operational review rather than causal proof.</p><div id="reportCategoryPlot" class="report-plot"></div>${ca.slice(0,8).map(c=>`<h3>${plain(c.category)}</h3><p>${plain(reportDomainNarrative(c,scoped))}</p>`).join('')}</div></div>
<div class="report-page"><div class="report-section"><h3>Resource-focus table</h3>${reportTable([{label:'Domain',key:'category',w:'22%'},{label:'Records',key:'n',num:true,w:'8%'},{label:'Projects',key:'projects',num:true,w:'8%'},{label:'Active',key:'active',num:true,w:'8%'},{label:'Overdue',key:'overdue',num:true,w:'8%'},{label:'>60 days active',key:'over60',num:true,w:'10%'},{label:'Late rate',f:c=>c.lateRate+'%',num:true,w:'8%'},{label:'Mean delay',f:c=>Math.round(c.meanDelay*10)/10+' days',num:true,w:'10%'},{label:'Score',key:'bottleneckScore',num:true,w:'8%'}],ca,24)}</div></div>
<div class="report-page"><div class="report-section"><h3>Thematic delayed-task analysis</h3><p>The chart and examples focus on delayed, overdue, over-target and long-active records. This helps distinguish whether the selected period is dominated by setup administration, finance, support departments, governance, activation, or first-patient delivery.</p><div id="reportThemePlot" class="report-plot"></div>${themes.slice(0,6).map(t=>{let ex=t.records.slice().sort((a,b)=>(b.elapsed||0)-(a.elapsed||0))[0]; return `<h3>${plain(t.name)}</h3><p>${plain(t.interpretation)} In this period it appears in ${t.n} delayed records across ${t.projectsN} projects; ${t.active} remain active and ${t.over60} are beyond 60 days active.${ex?` Example: ${ex.project} — ${ex.task} (${ex.elapsed??'–'} days, ${ex.taskStatus}).`:''}</p>`}).join('')}</div></div>
<div class="report-page"><div class="report-section"><h3>Priority active/pending records</h3><p>These are the records most likely to need near-term operational action because they are still open and/or longest-running. Comments are truncated for A4 fit; use the dashboard tables for full text.</p>${reportTable([{label:'Project',key:'project',w:'14%'},{label:'Domain',key:'category',w:'18%'},{label:'Task',key:'task',w:'24%'},{label:'Status',key:'taskStatus',w:'10%'},{label:'Elapsed',f:r=>(r.elapsed??'–')+' days',num:true,w:'8%'},{label:'Delay',f:r=>r.overTarget?`+${r.overTarget} days`:'',num:true,w:'8%'},{label:'Comment',f:r=>plain((r.taskComment||'').slice(0,150)),w:'18%'}],topActive,18)}</div></div>`; out.innerHTML=pages; status.textContent=`Report generated for ${scoped.length} records across ${pa.length} projects.`; setTimeout(()=>drawReportPlots(monthGroups,pa,ca,themes),80)}
function drawReportPlots(monthGroups,pa,ca,themes){plot('reportTrendPlot',[{type:'scatter',mode:'lines+markers',x:monthGroups.map(x=>x[0]),y:monthGroups.map(x=>x[1].length),name:'completed'},{type:'scatter',mode:'lines+markers',x:monthGroups.map(x=>x[0]),y:monthGroups.map(x=>x[1].filter(r=>r.timing==='Late').length),name:'late'}],{title:'Completed and late completed records by month',margin:{l:55,r:20,t:50,b:60},yaxis:{title:'records'}}); let setup=pa.filter(p=>Number.isFinite(p.startToGreen)).sort((a,b)=>b.startToGreen-a.startToGreen).slice(0,18).reverse(); plot('reportSetupPlot',[{type:'bar',orientation:'h',y:setup.map(p=>p.project),x:setup.map(p=>p.startToGreen),marker:{color:setup.map(p=>p.startToGreen>60?'#dc2626':'#15803d')}}],{title:'Projects with longest Start→C&C intervals',margin:{l:220,r:30,t:55,b:65},xaxis:{title:'days'},shapes:[{type:'line',x0:60,x1:60,y0:-0.5,y1:setup.length-0.5,line:{color:'#991b1b',dash:'dash'}}]}); let cats=ca.slice(0,14).reverse(); plot('reportCategoryPlot',[{type:'bar',orientation:'h',y:cats.map(c=>c.category),x:cats.map(c=>c.bottleneckScore),marker:{color:'#b45309'}}],{title:'Domains by resource/bottleneck score',margin:{l:280,r:30,t:55,b:65},xaxis:{title:'score'}}); let th=themes.slice(0,10).reverse(); plot('reportThemePlot',[{type:'bar',orientation:'h',y:th.map(t=>t.name),x:th.map(t=>t.n),name:'delayed records'},{type:'bar',orientation:'h',y:th.map(t=>t.name),x:th.map(t=>t.active),name:'active'}],{title:'Delayed-task themes',barmode:'stack',margin:{l:300,r:30,t:55,b:65},xaxis:{title:'records'}})}
async function waitForReportPlots(){let ids=['reportTrendPlot','reportSetupPlot','reportCategoryPlot','reportThemePlot']; await new Promise(r=>setTimeout(r,350)); for(let id of ids){let el=document.getElementById(id); if(el && el._promises && el._promises.length){try{await Promise.all(el._promises)}catch(e){}}}}
async function downloadReportPdf(){let status=document.getElementById('reportStatus'); try{if(!document.getElementById('reportOutput').innerHTML.trim()) generateReport(); if(status) status.textContent='Preparing PDF…'; await waitForReportPlots(); if(!window.html2canvas || !window.jspdf){throw new Error('PDF export libraries are still loading. Please wait a few seconds and try again.')} let pages=[...document.querySelectorAll('#reportOutput .report-page')]; if(!pages.length) throw new Error('No report pages found. Generate the report first.'); const {jsPDF}=window.jspdf; let pdf=new jsPDF({orientation:'portrait',unit:'mm',format:'a4',compress:true}); let pageW=210,pageH=297, margin=8, usableW=pageW-margin*2, footerY=291; for(let i=0;i<pages.length;i++){if(status) status.textContent=`Rendering PDF page ${i+1} of ${pages.length}…`; let page=pages[i]; let oldStyle=page.getAttribute('style')||''; page.style.width='1040px'; page.style.maxWidth='1040px'; page.style.border='0'; page.style.borderRadius='0'; let canvas=await html2canvas(page,{scale:1.6,backgroundColor:'#ffffff',useCORS:true,logging:false,windowWidth:1200}); page.setAttribute('style',oldStyle); if(i>0) pdf.addPage('a4','portrait'); let imgData=canvas.toDataURL('image/jpeg',0.92); let imgH=canvas.height*usableW/canvas.width; let maxImgH=pageH-margin*2-8; if(imgH<=maxImgH){pdf.addImage(imgData,'JPEG',margin,margin,usableW,imgH)}else{pdf.addImage(imgData,'JPEG',margin,margin,usableW,maxImgH)} pdf.setFontSize(8); pdf.setTextColor(110); pdf.text(`Page ${i+1} of ${pages.length}`,pageW-margin,footerY,{align:'right'});} let from=document.getElementById('reportFrom')?.value||'report', to=document.getElementById('reportTo')?.value||''; pdf.save(`rpeak-report-${from}${to?'-to-'+to:''}.pdf`); if(status) status.textContent=`PDF downloaded (${pages.length} pages).`;}catch(e){console.error(e); if(status) status.textContent=`PDF export failed: ${e.message}. Try the Print fallback button.`;}}
function printReportPdf(){if(!document.getElementById('reportOutput').innerHTML.trim()) generateReport(); document.querySelectorAll('.panel').forEach(x=>x.classList.remove('active')); document.getElementById('report').classList.add('active'); let status=document.getElementById('reportStatus'); if(status) status.textContent='Opening browser print dialog… if nothing appears, use Download PDF.'; setTimeout(()=>window.print(),450)}


function workflowAgg(){return [...group(rows,'workflow')].map(([workflow,rs])=>{let active=rs.filter(r=>r.isOpen), comp=rs.filter(r=>r.taskStatus==='Complete'), late=comp.filter(r=>r.timing==='Late'), matched=rs.filter(r=>r.matchScore!==null&&r.matchScore>=0.72); return {workflow,n:rs.length,projects:new Set(rs.map(r=>r.project)).size,active:active.length,complete:comp.length,late:late.length,lateRate:pct(late.length,comp.length||rs.length),medianElapsed:median(rs.map(r=>r.elapsed).filter(Number.isFinite)),meanElapsed:mean(rs.map(r=>r.elapsed).filter(Number.isFinite)),matched:matched.length,matchRate:pct(matched.length,rs.length),rows:rs}}).sort((a,b)=>b.n-a.n)}
function assigneeAgg(){return [...group(rows,r=>r.assignee||'Unassigned / not in extract')].map(([assignee,rs])=>{let active=rs.filter(r=>r.isOpen), comp=rs.filter(r=>r.taskStatus==='Complete'), late=comp.filter(r=>r.timing==='Late'); return {assignee,n:rs.length,projects:new Set(rs.map(r=>r.project)).size,workflows:new Set(rs.map(r=>r.workflow)).size,taskTypes:new Set(rs.map(r=>r.taskType)).size,active:active.length,complete:comp.length,late:late.length,lateRate:pct(late.length,comp.length||rs.length),medianElapsed:median(rs.map(r=>r.elapsed).filter(Number.isFinite)),meanElapsed:mean(rs.map(r=>r.elapsed).filter(Number.isFinite)),rows:rs}}).sort((a,b)=>b.n-a.n)}
function initWorkflow(){document.getElementById('workflowTemplateFile')?.addEventListener('change',handleWorkflowTemplateUpload); let meta=workflowTemplateMeta(), st=document.getElementById('workflowTemplateStatus'); if(st) st.innerHTML=workflowTemplate.length?`Using workflow template: <b>${esc(meta.name||'uploaded template')}</b> (${workflowTemplate.length} task definitions${meta.bundled?' bundled':''}). Fuzzy matches ≥72% are treated as matched; lower scores remain transparent in the audit tab.`:'No workflow task-order template loaded yet. Project Gantts use observed ordering until you upload the workflow Excel file.'; let data=workflowAgg(); let top=data.slice(0,18).reverse(), labels=barLabels(top.map(x=>x.workflow),38); plot('workflowVolumePlot',[{type:'bar',orientation:'h',y:labels,x:top.map(x=>x.n),name:'all records'},{type:'bar',orientation:'h',y:labels,x:top.map(x=>x.active),name:'active'}],{title:'Records by workflow',barmode:'stack',...horizontalBarLayout(labels,{xaxis:{title:'records'}})}); let slow=data.slice().sort((a,b)=>(b.meanElapsed||0)-(a.meanElapsed||0)).slice(0,18).reverse(), slowLabels=barLabels(slow.map(x=>x.workflow),38); plot('workflowDelayPlot',[{type:'bar',orientation:'h',y:slowLabels,x:slow.map(x=>Math.round((x.meanElapsed||0)*10)/10),marker:{color:'#b45309'}}],{title:'Workflow by mean elapsed / active days',...horizontalBarLayout(slowLabels,{xaxis:{title:'days'}})}); renderTable('workflowTable',[{label:'Workflow',key:'workflow'},{label:'Projects',key:'projects'},{label:'Records',key:'n'},{label:'Active',key:'active'},{label:'Complete',key:'complete'},{label:'Late rate',f:w=>w.lateRate+'%',sort:w=>w.lateRate},{label:'Median elapsed',f:w=>(w.medianElapsed??'–')+' days',sort:w=>w.medianElapsed??-1},{label:'Template match rate',f:w=>w.matchRate+'%',sort:w=>w.matchRate}],data,200)}
function initOwnership(){let data=assigneeAgg(); let top=data.slice(0,18).reverse(), labels=barLabels(top.map(x=>x.assignee),38); plot('assigneeWorkloadPlot',[{type:'bar',orientation:'h',y:labels,x:top.map(x=>x.n),name:'all records'},{type:'bar',orientation:'h',y:labels,x:top.map(x=>x.active),name:'active'}],{title:'Workload by assigned owner',barmode:'stack',...horizontalBarLayout(labels,{xaxis:{title:'records'}})}); let slow=data.slice().sort((a,b)=>(b.meanElapsed||0)-(a.meanElapsed||0)).slice(0,18).reverse(), sl=barLabels(slow.map(x=>x.assignee),38); plot('assigneeDelayPlot',[{type:'bar',orientation:'h',y:sl,x:slow.map(x=>Math.round((x.meanElapsed||0)*10)/10),marker:{color:'#dc2626'}}],{title:'Assigned owner by mean elapsed / active days',...horizontalBarLayout(sl,{xaxis:{title:'days'}})}); renderTable('assigneeTable',[{label:'Assigned to',key:'assignee'},{label:'Projects',key:'projects'},{label:'Workflows',key:'workflows'},{label:'Task types',key:'taskTypes'},{label:'Records',key:'n'},{label:'Active',key:'active'},{label:'Late rate',f:a=>a.lateRate+'%',sort:a=>a.lateRate},{label:'Median elapsed',f:a=>(a.medianElapsed??'–')+' days',sort:a=>a.medianElapsed??-1}],data,200)}
function qualityRows(){return rows.map(r=>{let missing=[]; if(!r.hraDate)missing.push('HRA approval date'); if(!r.startDate)missing.push('Task start date'); if(!r.dueDate)missing.push('Due date'); if(!r.completionDate&&r.taskStatus==='Complete')missing.push('Completion date for completed task'); if(!Number.isFinite(r.targetDays))missing.push('Target days'); if(!r.assignee||r.assignee==='Unassigned / not in extract')missing.push('Assignee'); if(workflowTemplate.length && !(r.matchScore>=0.72))missing.push('Workflow template match'); let impute=[]; if(!r.hraDate)impute.push(`Start date fallback: ${r.anchorSource}`); if(!Number.isFinite(r.workflowOrder))impute.push('Observed task order used'); if(!r.assignee||r.assignee==='Unassigned / not in extract')impute.push('Assignee unavailable'); return {...r,missingText:missing.join('; ')||'None flagged',imputationText:impute.join('; ')||'None',matchLabel:r.matchScore===null?'No template':Math.round(r.matchScore*100)+'%'}})}
function initQuality(){let qr=qualityRows(); let metrics=[['HRA approval date missing',qr.filter(r=>!r.hraDate).length],['Assignee missing/not in extract',qr.filter(r=>r.assignee==='Unassigned / not in extract').length],['Due date missing',qr.filter(r=>!r.dueDate).length],['Target days missing',qr.filter(r=>!Number.isFinite(r.targetDays)).length],['Workflow-template unmatched',workflowTemplate.length?qr.filter(r=>!(r.matchScore>=0.72)).length:0]]; plot('missingnessPlot',[{type:'bar',orientation:'h',y:metrics.map(x=>x[0]).reverse(),x:metrics.map(x=>x[1]).reverse(),marker:{color:'#b45309'}}],{title:'Missingness flags',margin:{l:210,r:30,t:55,b:70},xaxis:{title:'records'}}); let imps=[...group(qr,r=>r.anchorSource)].map(([k,v])=>({k,n:v.length})).sort((a,b)=>b.n-a.n).reverse(); plot('imputationPlot',[{type:'bar',orientation:'h',y:imps.map(x=>x.k),x:imps.map(x=>x.n),marker:{color:'#2563eb'}}],{title:'Start date source used',margin:{l:210,r:30,t:55,b:70},xaxis:{title:'records'}}); renderTable('qualityTable',[{label:'Project',key:'project'},{label:'Workflow',key:'workflow'},{label:'Task',key:'task'},{label:'Template task',key:'templateTask'},{label:'Match',key:'matchLabel',sort:r=>r.matchScore??-1},{label:'Order',f:r=>r.workflowOrder??'',sort:r=>r.workflowOrder??9999},{label:'Start date used',key:'anchorSource'},{label:'Assigned to',key:'assignee'},{label:'Missingness',key:'missingText'},{label:'Imputations/fallbacks',key:'imputationText'}],qr,2000)}
function clearWorkflowTemplate(){localStorage.removeItem(WORKFLOW_TEMPLATE_KEY); localStorage.removeItem(WORKFLOW_TEMPLATE_META_KEY); location.reload()}
function normaliseWorkflowTemplate(inputRows){let headers=Object.keys(inputRows[0]||{}); let h={workflow:bestColumn(headers,['workflow','pathway','route']),task:bestColumn(headers,['task name','task','activity','milestone','step']),order:bestColumn(headers,['order','sequence','task order','sort','position','number']),taskType:bestColumn(headers,['task type','type','category','domain']),assignee:bestColumn(headers,['assigned to','assignee','owner','responsible','team','role'])}; return inputRows.map((r,i)=>({workflow:h.workflow?String(r[h.workflow]??'').trim():'',task:h.task?String(r[h.task]??'').trim():'',order:num(h.order?String(r[h.order]??''):'')??(i+1),taskType:h.taskType?String(r[h.taskType]??'').trim():'',assignee:h.assignee?String(r[h.assignee]??'').trim():''})).filter(r=>r.task)}
async function handleWorkflowTemplateUpload(ev){let file=ev.target.files?.[0]; if(!file)return; let st=document.getElementById('workflowTemplateStatus'); try{if(st)st.textContent='Reading workflow template…'; let buf=await file.arrayBuffer(); let wb=XLSX.read(buf,{type:'array',cellDates:true}); let chosen=chooseRelevantSheet(wb); let tmpl=normaliseWorkflowTemplate(chosen.rows); if(!tmpl.length)throw new Error('No workflow task rows found'); localStorage.setItem(WORKFLOW_TEMPLATE_KEY,JSON.stringify(tmpl)); localStorage.setItem(WORKFLOW_TEMPLATE_META_KEY,JSON.stringify({name:file.name,sheet:chosen.name,nRows:tmpl.length})); location.reload()}catch(e){if(st)st.textContent=`Could not import workflow template: ${e.message}`; console.error(e)}}

function initRaw(){document.getElementById('rawSearch').addEventListener('input',renderRaw); document.getElementById('uploadFile')?.addEventListener('change',handleUpload); let status=document.getElementById('uploadStatus'); if(status){let meta=currentDataMeta(); status.innerHTML=meta.uploaded?`Using uploaded data: <b>${esc(meta.name)}</b> (${RAW.length} rows). <span class="muted">${esc(meta.note||'')}${meta.storageMb?' · stored compactly: '+esc(meta.storageMb)+' MB':''}</span>`:`Using bundled source data (${RAW.length} rows).`} renderRaw()}
function renderRaw(){let q=document.getElementById('rawSearch').value.toLowerCase(); let data=rows.filter(r=>!q||Object.values(r).join(' ').toLowerCase().includes(q)); let cols=DATA_FIELDS.map(c=>({label:c,f:r=>esc(r[c]||'')})); renderTable('rawTable',cols,data,1500)}
document.querySelectorAll('.tabs .tab[data-tab]').forEach(b=>b.onclick=()=>{document.querySelectorAll('.tabs .tab[data-tab],.panel').forEach(x=>x.classList.remove('active')); b.classList.add('active'); document.getElementById(b.dataset.tab).classList.add('active'); if(b.dataset.tab==='themes') initThemes(); if(b.dataset.tab==='workflow') initWorkflow(); if(b.dataset.tab==='ownership') initOwnership(); if(b.dataset.tab==='quality') initQuality(); if(b.dataset.tab==='report') initReport(); setTimeout(()=>window.dispatchEvent(new Event('resize')),50)});
initOverview(); initProjects(); initTasks(); initWorkflow(); initOwnership(); initBottlenecks(); initThemes(); initQuality(); initRaw(); initReport();
